import { useCallback, useEffect, useMemo, useState } from "react";

const STORAGE_KEY = "calchive-favorites";
const FAVORITES_EVENT = "calchive:favorites";

function readFavorites() {
  if (typeof window === "undefined") return [];
  try {
    const parsed = JSON.parse(window.localStorage.getItem(STORAGE_KEY) || "[]");
    return Array.isArray(parsed) ? parsed.filter((item): item is string => typeof item === "string") : [];
  } catch {
    return [];
  }
}

function writeFavorites(items: string[]) {
  window.localStorage.setItem(STORAGE_KEY, JSON.stringify(items));
  window.dispatchEvent(new Event(FAVORITES_EVENT));
}

export function useFavorites() {
  const [favorites, setFavorites] = useState<string[]>([]);
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    const sync = () => setFavorites(readFavorites());
    sync();
    setMounted(true);
    window.addEventListener("storage", sync);
    window.addEventListener(FAVORITES_EVENT, sync);
    return () => {
      window.removeEventListener("storage", sync);
      window.removeEventListener(FAVORITES_EVENT, sync);
    };
  }, []);

  const toggleFavorite = useCallback((href: string) => {
    setFavorites((current) => {
      const exists = current.includes(href);
      const next = exists ? current.filter((item) => item !== href) : [href, ...current];
      writeFavorites(next);
      return next;
    });
  }, []);

  const favoriteSet = useMemo(() => new Set(favorites), [favorites]);

  return {
    favorites,
    favoriteSet,
    count: favorites.length,
    mounted,
    isFavorite: useCallback((href: string) => favoriteSet.has(href), [favoriteSet]),
    toggleFavorite,
  };
}
