const HomeSections = lazy(() => import("@/pages/HomeSections"));

type HomeSectionTool = {
  href: string;
  title: string;
  category: string;
  Icon: LucideIcon;
  color: string;
};

function DeferredHomeSections({ toolsCount, tools }: { toolsCount: number; tools: HomeSectionTool[] }) {
  const [shouldRender, setShouldRender] = useState(false);
  const markerRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    if (shouldRender) return;

    const idleWindow = window as Window & typeof globalThis & {
      requestIdleCallback?: (callback: () => void, options?: { timeout?: number }) => number;
      cancelIdleCallback?: (handle: number) => void;
    };
    let idleHandle: number | undefined;
    let timeoutHandle: number | undefined;
    let observer: IntersectionObserver | undefined;

    const reveal = () => setShouldRender(true);

    if ("IntersectionObserver" in window && markerRef.current) {
      observer = new IntersectionObserver(
        (entries) => {
          if (entries.some((entry) => entry.isIntersecting)) {
            observer?.disconnect();
            reveal();
          }
        },
        { rootMargin: "900px 0px" },
      );
      observer.observe(markerRef.current);
    }

    timeoutHandle = window.setTimeout(() => {
      idleHandle = idleWindow.requestIdleCallback
        ? idleWindow.requestIdleCallback(reveal, { timeout: 3000 })
        : window.setTimeout(reveal, 1800);
    }, 900);

    return () => {
      observer?.disconnect();
      if (idleHandle !== undefined) {
        idleWindow.cancelIdleCallback?.(idleHandle);
        window.clearTimeout(idleHandle);
      }
      if (timeoutHandle !== undefined) window.clearTimeout(timeoutHandle);
    };
  }, [shouldRender]);

  return (
    <div ref={markerRef}>
      {shouldRender ? (
        <>
          <Suspense fallback={null}>
            <HomeSections toolsCount={toolsCount} tools={tools} />
          </Suspense>
        </>
      ) : null}
    </div>
  );
}

