import { useEffect } from "react";

export default function HomeScrollMotion() {
  useEffect(() => {
    const reduceMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
    const items = new Set<HTMLElement>();
    const observers: IntersectionObserver[] = [];

    const prepareItem = (item: HTMLElement, index = items.size) => {
      if (items.has(item)) return;
      items.add(item);
      item.classList.add("home-reveal");
      item.style.setProperty("--home-delay", `${Math.min((index % 8) * 42, 210)}ms`);
      if (reduceMotion || !("IntersectionObserver" in window)) {
        item.classList.add("home-reveal-in");
        return;
      }

      observer.observe(item);
    };

    const finePointer = window.matchMedia("(hover: hover) and (pointer: fine)").matches;
    let activeCard: HTMLElement | null = null;
    let raf = 0;
    let lastPointerX = 0;
    let lastPointerY = 0;

    const updatePointerGlow = () => {
      raf = 0;
      if (!activeCard) return;
      const rect = activeCard.getBoundingClientRect();
      const localX = lastPointerX - rect.left;
      const localY = lastPointerY - rect.top;
      const tiltX = ((0.5 - localY / rect.height) * 3.2).toFixed(2);
      const tiltY = ((localX / rect.width - 0.5) * 4.2).toFixed(2);
      activeCard.style.setProperty("--home-x", `${localX}px`);
      activeCard.style.setProperty("--home-y", `${localY}px`);
      activeCard.style.setProperty("--home-tilt-x", `${tiltX}deg`);
      activeCard.style.setProperty("--home-tilt-y", `${tiltY}deg`);
    };

    const onPointerMove = (event: PointerEvent) => {
      const target = (event.target as Element | null)?.closest<HTMLElement>("[data-home-card]");
      if (!target) {
        activeCard?.removeAttribute("data-home-active");
        activeCard = null;
        return;
      }
      if (activeCard !== target) {
        activeCard?.removeAttribute("data-home-active");
        activeCard = target;
        activeCard.setAttribute("data-home-active", "true");
      }
      lastPointerX = event.clientX;
      lastPointerY = event.clientY;
      if (!raf) raf = window.requestAnimationFrame(updatePointerGlow);
    };

    const onPointerLeave = () => {
      activeCard?.removeAttribute("data-home-active");
      activeCard = null;
    };

    const prepareAll = () => {
      document.querySelectorAll<HTMLElement>("[data-home-reveal]").forEach((item, index) => {
        prepareItem(item, index);
      });
    };

    if (reduceMotion || !("IntersectionObserver" in window)) {
      prepareAll();
      return;
    }

    let ticking = false;
    const revealVisible = () => {
      ticking = false;
      const limit = window.innerHeight * 0.9;
      items.forEach((item) => {
        if (item.classList.contains("home-reveal-in")) return;
        const rect = item.getBoundingClientRect();
        if (rect.top < limit && rect.bottom > 0) {
          item.classList.add("home-reveal-in");
        }
      });
    };

    const queueReveal = () => {
      if (ticking) return;
      ticking = true;
      window.requestAnimationFrame(revealVisible);
    };

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (!entry.isIntersecting) return;
          entry.target.classList.add("home-reveal-in");
          observer.unobserve(entry.target);
        });
      },
      { rootMargin: "0px 0px -8% 0px", threshold: 0.08 }
    );

    const mutationObserver = new MutationObserver(() => {
      prepareAll();
      queueReveal();
    });

    prepareAll();
    observers.push(observer);
    mutationObserver.observe(document.body, { childList: true, subtree: true });
    queueReveal();
    window.addEventListener("scroll", queueReveal, { passive: true });
    window.addEventListener("resize", queueReveal, { passive: true });
    if (finePointer) {
      document.addEventListener("pointermove", onPointerMove, { passive: true });
      document.addEventListener("pointerleave", onPointerLeave, { passive: true });
    }

    return () => {
      observers.forEach((entry) => entry.disconnect());
      mutationObserver.disconnect();
      window.removeEventListener("scroll", queueReveal);
      window.removeEventListener("resize", queueReveal);
      if (finePointer) {
        document.removeEventListener("pointermove", onPointerMove);
        document.removeEventListener("pointerleave", onPointerLeave);
      }
      if (raf) window.cancelAnimationFrame(raf);
    };
  }, []);

  return (
    <style>{`
      [data-home-reveal] {
        opacity: 1;
      }

      .home-reveal {
        opacity: 0;
        transform: translate3d(0, 30px, 0) scale(.975);
        transition:
          opacity 720ms cubic-bezier(.16,1,.3,1),
          transform 720ms cubic-bezier(.16,1,.3,1),
          box-shadow 260ms ease,
          border-color 260ms ease,
          background-color 260ms ease;
        transition-delay: var(--home-delay, 0ms);
        will-change: opacity, transform;
      }

      .home-reveal[data-home-motion="left"] {
        transform: translate3d(-34px, 18px, 0) scale(.982);
      }

      .home-reveal[data-home-motion="right"] {
        transform: translate3d(34px, 18px, 0) scale(.982);
      }

      .home-reveal[data-home-motion="pop"] {
        transform: translate3d(0, 26px, 0) scale(.94);
      }

      .home-reveal[data-home-motion="draw"] {
        opacity: 1;
        transform: scaleX(0);
        transform-origin: left;
      }

      .home-reveal-in,
      .home-reveal-in[data-home-motion="left"],
      .home-reveal-in[data-home-motion="right"],
      .home-reveal-in[data-home-motion="pop"] {
        opacity: 1;
        transform: translate3d(0, 0, 0) scale(1);
      }

      .home-reveal-in[data-home-motion="draw"] {
        opacity: 1;
        transform: scaleX(1);
      }

      .home-reveal-in[data-home-motion="pop"] {
        animation: home-pop-settle 560ms cubic-bezier(.2,1.35,.32,1) both;
      }

      .calchive-home-motion :where([data-home-card]) {
        position: relative;
        overflow: hidden;
        isolation: isolate;
        backface-visibility: hidden;
        transform-style: preserve-3d;
        box-shadow: 0 1px 1px hsl(var(--foreground) / .03);
      }

      .calchive-home-motion [data-home-card] > * {
        position: relative;
        z-index: 1;
      }

      .calchive-home-motion [data-home-card]::after {
        content: "";
        position: absolute;
        inset: 0;
        z-index: 0;
        pointer-events: none;
        opacity: 0;
        background:
          linear-gradient(115deg, transparent 0%, hsl(var(--primary) / .08) 36%, hsl(var(--primary) / .16) 48%, transparent 62%),
          radial-gradient(circle at var(--home-x, 50%) var(--home-y, 0%), hsl(var(--primary) / .13), transparent 38%);
        transform: translate3d(-18%, 0, 0);
        transition: opacity 280ms ease, transform 520ms cubic-bezier(.16,1,.3,1);
      }

      .calchive-home-motion [data-home-card]:where(:hover, [data-home-active="true"])::after {
        opacity: 1;
        transform: translate3d(0, 0, 0);
      }

      .calchive-home-motion .home-reveal-in[data-home-card]:where(:hover, [data-home-active="true"]) {
        transform: translate3d(0, -6px, 0) scale(1.012);
        border-color: hsl(var(--primary) / .32);
        box-shadow:
          0 18px 46px hsl(var(--primary) / .10),
          0 8px 18px hsl(var(--foreground) / .08);
      }

      .calchive-home-motion [data-home-glow]::before {
        content: "";
        position: absolute;
        inset: -1px;
        z-index: 0;
        opacity: 0;
        pointer-events: none;
        background:
          radial-gradient(circle at var(--home-x, 30%) var(--home-y, 15%), hsl(var(--primary) / .18), transparent 34%),
          radial-gradient(circle at 80% 10%, hsl(199 89% 48% / .10), transparent 38%);
        transition: opacity 260ms ease;
      }

      .calchive-home-motion [data-home-glow]:where(:hover, [data-home-active="true"])::before {
        opacity: 1;
      }

      .calchive-home-motion [data-home-card]:active {
        transform: translate3d(0, -2px, 0) scale(.992);
      }

      @media (min-width: 768px) and (hover: hover) and (pointer: fine) {
        .calchive-home-hero-desktop::before {
          content: "";
          position: absolute;
          inset: 0;
          z-index: 0;
          pointer-events: none;
          opacity: .72;
          background:
            radial-gradient(circle at 14% 24%, hsl(var(--primary) / .16), transparent 32%),
            radial-gradient(circle at 80% 18%, hsl(199 89% 48% / .12), transparent 34%),
            linear-gradient(115deg, transparent 22%, hsl(var(--primary) / .055) 46%, transparent 72%);
          animation: home-hero-ambient 13s cubic-bezier(.45,0,.2,1) infinite alternate;
        }

        .calchive-home-hero-desktop::after {
          content: "";
          position: absolute;
          top: 0;
          left: -28%;
          z-index: 1;
          width: 28%;
          height: 100%;
          pointer-events: none;
          opacity: .34;
          background: linear-gradient(90deg, transparent, hsl(var(--primary) / .16), transparent);
          transform: skewX(-16deg);
          animation: home-hero-sweep 9s ease-in-out infinite;
        }

        .calchive-home-hero-desktop > .max-w-6xl {
          position: relative;
          z-index: 2;
          animation: home-desktop-hero-lift 620ms cubic-bezier(.16,1,.3,1) both;
        }

        .calchive-home-hero-desktop .home-hero-copy > * {
          animation: home-desktop-copy-in 640ms cubic-bezier(.16,1,.3,1) both;
        }

        .calchive-home-hero-desktop .home-hero-copy > *:nth-child(1) { animation-delay: 40ms; }
        .calchive-home-hero-desktop .home-hero-copy > *:nth-child(2) { animation-delay: 90ms; }
        .calchive-home-hero-desktop .home-hero-copy > *:nth-child(3) { animation-delay: 140ms; }
        .calchive-home-hero-desktop .home-hero-copy > *:nth-child(4) { animation-delay: 190ms; }
        .calchive-home-hero-desktop .home-hero-copy > *:nth-child(5) { animation-delay: 235ms; }
        .calchive-home-hero-desktop .home-hero-copy > *:nth-child(6) { animation-delay: 275ms; }
        .calchive-home-hero-desktop .home-hero-copy > *:nth-child(7) { animation-delay: 315ms; }

        .calchive-home-hero-desktop .home-hero-calculator {
          animation: home-desktop-calc-in 760ms cubic-bezier(.16,1,.3,1) 180ms both;
          transform-origin: 50% 60%;
        }

        .calchive-home-hero-desktop .home-hero-popular a {
          position: relative;
          overflow: hidden;
        }

        .calchive-home-hero-desktop .home-hero-popular a::after {
          content: "";
          position: absolute;
          inset: 0;
          opacity: 0;
          pointer-events: none;
          background: linear-gradient(115deg, transparent 20%, hsl(var(--primary) / .16) 50%, transparent 78%);
          transform: translateX(-110%);
          transition: opacity 180ms ease, transform 460ms cubic-bezier(.16,1,.3,1);
        }

        .calchive-home-hero-desktop .home-hero-popular a:hover::after {
          opacity: 1;
          transform: translateX(110%);
        }

        .calchive-home-motion {
          position: relative;
        }

        .calchive-home-motion::before {
          content: "";
          position: absolute;
          top: 0;
          left: 0;
          right: 0;
          z-index: 0;
          height: 1px;
          pointer-events: none;
          opacity: .54;
          background: linear-gradient(90deg, transparent, hsl(var(--primary) / .35), hsl(199 89% 48% / .24), transparent);
          background-size: 220% 100%;
          animation: home-section-line 10s linear infinite;
        }

        .calchive-home-motion .home-reveal-in[data-home-card]:where(:hover, [data-home-active="true"]) {
          transform:
            perspective(900px)
            rotateX(var(--home-tilt-x, 0deg))
            rotateY(var(--home-tilt-y, 0deg))
            translate3d(0, -8px, 0)
            scale(1.014);
          box-shadow:
            0 24px 60px hsl(var(--primary) / .13),
            0 10px 24px hsl(var(--foreground) / .10),
            inset 0 1px 0 hsl(var(--background) / .55);
        }

        .calchive-home-motion [data-home-card]::after {
          background:
            linear-gradient(115deg, transparent 0%, hsl(var(--primary) / .06) 30%, hsl(var(--primary) / .20) 48%, transparent 66%),
            radial-gradient(circle at var(--home-x, 50%) var(--home-y, 0%), hsl(var(--primary) / .20), transparent 36%),
            radial-gradient(circle at calc(var(--home-x, 50%) + 90px) calc(var(--home-y, 0%) + 70px), hsl(199 89% 48% / .10), transparent 38%);
        }

        .calchive-home-motion [data-home-card]:where(:hover, [data-home-active="true"])::after {
          animation: home-card-sheen 820ms cubic-bezier(.16,1,.3,1) both;
        }
      }

      @keyframes home-pop-settle {
        0% { transform: translate3d(0, 26px, 0) scale(.94); }
        68% { transform: translate3d(0, -2px, 0) scale(1.012); }
        100% { transform: translate3d(0, 0, 0) scale(1); }
      }

      @keyframes home-desktop-hero-lift {
        0% { opacity: .82; transform: translate3d(0, 14px, 0); }
        100% { opacity: 1; transform: translate3d(0, 0, 0); }
      }

      @keyframes home-desktop-copy-in {
        0% { opacity: 0; transform: translate3d(-14px, 16px, 0); }
        100% { opacity: 1; transform: translate3d(0, 0, 0); }
      }

      @keyframes home-desktop-calc-in {
        0% { opacity: 0; transform: translate3d(26px, 22px, 0) scale(.975); }
        100% { opacity: 1; transform: translate3d(0, 0, 0) scale(1); }
      }

      @keyframes home-hero-ambient {
        0% { transform: translate3d(-1.5%, -1%, 0) scale(1); opacity: .58; }
        100% { transform: translate3d(1.5%, 1%, 0) scale(1.025); opacity: .78; }
      }

      @keyframes home-hero-sweep {
        0%, 42% { transform: translateX(0) skewX(-16deg); opacity: 0; }
        55% { opacity: .34; }
        78%, 100% { transform: translateX(520%) skewX(-16deg); opacity: 0; }
      }

      @keyframes home-section-line {
        0% { background-position: 220% 0; }
        100% { background-position: -220% 0; }
      }

      @keyframes home-card-sheen {
        0% { opacity: 0; transform: translate3d(-22%, 0, 0); }
        35% { opacity: 1; }
        100% { opacity: 1; transform: translate3d(0, 0, 0); }
      }

      @media (max-width: 640px) {
        .home-reveal,
        .home-reveal[data-home-motion="left"],
        .home-reveal[data-home-motion="right"],
        .home-reveal[data-home-motion="pop"] {
          transform: translate3d(0, 18px, 0) scale(.982);
          transition-duration: 430ms;
          transition-delay: min(var(--home-delay, 0ms), 110ms);
        }

        .home-reveal-in[data-home-motion="pop"] {
          animation-duration: 380ms;
        }

        .calchive-home-motion .home-reveal-in[data-home-card]:where(:hover, [data-home-active="true"]) {
          transform: none;
          box-shadow: 0 1px 1px hsl(var(--foreground) / .03);
        }

        .calchive-home-motion [data-home-glow]::before,
        .calchive-home-motion [data-home-card]::after,
        .calchive-home-hero-desktop::before,
        .calchive-home-hero-desktop::after {
          display: none;
        }
      }

      @media (prefers-reduced-motion: reduce) {
        .home-reveal,
        .home-reveal[data-home-motion="left"],
        .home-reveal[data-home-motion="right"],
        .home-reveal[data-home-motion="pop"],
        .home-reveal[data-home-motion="draw"] {
          opacity: 1 !important;
          transform: none !important;
          animation: none !important;
          transition: none !important;
          will-change: auto !important;
        }
        .calchive-home-hero-desktop::before,
        .calchive-home-hero-desktop::after,
        .calchive-home-motion::before {
          animation: none !important;
        }
        .calchive-home-hero-desktop > .max-w-6xl,
        .calchive-home-hero-desktop .home-hero-copy > *,
        .calchive-home-hero-desktop .home-hero-calculator {
          animation: none !important;
        }
      }
    `}</style>
  );
}
