import { useState, useCallback } from "react";

type AngleMode = "deg" | "rad";

type State = {
  display: string;
  expr: string;
  justComputed: boolean;
  memory: number;
  lastAnswer: string;
  angleMode: AngleMode;
};

type Btn = {
  key: string;
  label: string;
  type: "sci" | "op" | "num" | "eq" | "mem" | "fn";
  sup?: string;
  pre?: string;
  label2?: string;
  cols?: number;
};

const OPERATOR_LABELS: Record<string, string> = {
  "*": "x",
  "/": "/",
};

const OPERATOR_ARIA_LABELS: Record<string, string> = {
  "+": "Add",
  "-": "Subtract",
  "*": "Multiply",
  "/": "Divide",
  "=": "Equals",
};

const INIT: State = {
  display: "0",
  expr: "",
  justComputed: false,
  memory: 0,
  lastAnswer: "0",
  angleMode: "deg",
};

function fmt(n: number): string {
  if (!isFinite(n) || isNaN(n)) return "Error";
  if (n === 0) return "0";
  const abs = Math.abs(n);
  if (abs >= 1e13 || (abs < 1e-9 && abs > 0))
    return parseFloat(n.toPrecision(10)).toExponential(6).replace(/\.?0+(e)/, "$1");
  const rounded = parseFloat(n.toPrecision(10));
  return rounded.toFixed(10).replace(/(\.\d*?)0+$/, "$1").replace(/\.$/, "");
}

function toRad(x: number, mode: AngleMode) {
  return mode === "deg" ? (x * Math.PI) / 180 : x;
}
function fromRad(x: number, mode: AngleMode) {
  return mode === "deg" ? (x * 180) / Math.PI : x;
}
function factorial(n: number): number {
  if (!Number.isInteger(n) || n < 0 || n > 170) return NaN;
  let r = 1;
  for (let i = 2; i <= n; i++) r *= i;
  return r;
}
function safeEval(expr: string): string {
  try {
    const e = expr
      .replace(/pi/g, String(Math.PI))
      .replace(/\^/g, "**");
    // eslint-disable-next-line no-new-func
    const r = Function('"use strict"; return (' + e + ")")() as number;
    return fmt(r);
  } catch { return "Error"; }
}

// Scientific desktop rows (10-col)
const SCI_ROWS: Btn[][] = [
  [
    { key: "sin",  label: "sin",   type: "sci" },
    { key: "cos",  label: "cos",   type: "sci" },
    { key: "tan",  label: "tan",   type: "sci" },
    { key: "7",    label: "7",     type: "num" },
    { key: "8",    label: "8",     type: "num" },
    { key: "9",    label: "9",     type: "num" },
    { key: "+",    label: "+",     type: "op"  },
    { key: "Back", label: "Back",  type: "sci" },
  ],
  [
    { key: "asin", label: "sin", sup: "-1", type: "sci" },
    { key: "acos", label: "cos", sup: "-1", type: "sci" },
    { key: "atan", label: "tan", sup: "-1", type: "sci" },
    { key: "pi",    label: "pi",   type: "sci" },
    { key: "e",    label: "e",   type: "sci" },
    { key: "4",    label: "4",   type: "num" },
    { key: "5",    label: "5",   type: "num" },
    { key: "6",    label: "6",   type: "num" },
    { key: "-",    label: "-",   type: "op"  },
    { key: "Ans",  label: "Ans", type: "mem" },
  ],
  [
    { key: "pow",  label: "x", sup: "y",  type: "sci" },
    { key: "cube", label: "x", sup: "3",  type: "sci" },
    { key: "sq",   label: "x", sup: "2",  type: "sci" },
    { key: "exp",  label: "e", sup: "x",  type: "sci" },
    { key: "10x",  label: "10", sup: "x", type: "sci" },
    { key: "1",    label: "1",  type: "num" },
    { key: "2",    label: "2",  type: "num" },
    { key: "3",    label: "3",  type: "num" },
    { key: "*",    label: OPERATOR_LABELS["*"],  type: "op"  },
    { key: "M+",   label: "M+", type: "mem" },
  ],
  [
    { key: "yroot", label: "", pre: "y", sup: "", label2: "root", type: "sci" },
    { key: "cbrt",  label: "", pre: "3", sup: "", label2: "root", type: "sci" },
    { key: "sqrt",  label: "sqrt",  type: "sci" },
    { key: "ln",    label: "ln",  type: "sci" },
    { key: "log",   label: "log", type: "sci" },
    { key: "0",     label: "0",   type: "num" },
    { key: ".",     label: ".",   type: "num" },
    { key: "EXP",   label: "EXP", type: "sci" },
    { key: "/",     label: OPERATOR_LABELS["/"],   type: "op"  },
    { key: "M-",    label: "M-", type: "mem" },
  ],
  [
    { key: "(",   label: "(",   type: "sci" },
    { key: ")",   label: ")",   type: "sci" },
    { key: "1/x", label: "1/x", type: "sci" },
    { key: "%",   label: "%",   type: "sci" },
    { key: "n!",  label: "n!",  type: "sci" },
    { key: "neg", label: "+/-", type: "sci" },
    { key: "RND", label: "RND", type: "sci" },
    { key: "AC",  label: "AC",  type: "sci" },
    { key: "=",   label: "=",   type: "eq"  },
    { key: "MR",  label: "MR",  type: "mem" },
  ],
];

// Mobile basic rows (4-col)
// Row 1: AC  +/-  %   /
// Row 2: 7   8  9   x
// Row 3: 4   5  6  -
// Row 4: 1   2  3  +
// Row 5: Back  0  .  =
const MOB_ROWS: (Btn & { cols?: number })[][] = [
  [
    { key: "AC",  label: "AC",  type: "fn" },
    { key: "neg", label: "+/-", type: "fn" },
    { key: "%",   label: "%",   type: "fn" },
    { key: "/",   label: OPERATOR_LABELS["/"],   type: "op" },
  ],
  [
    { key: "7",   label: "7",   type: "num" },
    { key: "8",   label: "8",   type: "num" },
    { key: "9",   label: "9",   type: "num" },
    { key: "*",   label: OPERATOR_LABELS["*"],   type: "op"  },
  ],
  [
    { key: "4",   label: "4",   type: "num" },
    { key: "5",   label: "5",   type: "num" },
    { key: "6",   label: "6",   type: "num" },
    { key: "-",   label: "-",   type: "op"  },
  ],
  [
    { key: "1",   label: "1",   type: "num" },
    { key: "2",   label: "2",   type: "num" },
    { key: "3",   label: "3",   type: "num" },
    { key: "+",   label: "+",   type: "op"  },
  ],
  [
    { key: "Back", label: "Back", type: "fn" },
    { key: "0",    label: "0",  type: "num" },
    { key: ".",    label: ".",  type: "num" },
    { key: "=",    label: "=",  type: "eq"  },
  ],
];

function BtnLabel({ btn }: { btn: Btn }) {
  const b = btn as Btn & { label2?: string };
  if (b.pre !== undefined && b.label2) {
    return (
      <span className="flex items-end leading-none">
        <sup className="text-[8px] leading-none mr-0.5">{b.pre}</sup>
        <span>{b.label2}</span>
      </span>
    );
  }
  if (btn.sup) {
    return (
      <span className="flex items-end leading-none">
        <span>{btn.label}</span>
        <sup className="text-[8px] leading-none">{btn.sup}</sup>
      </span>
    );
  }
  return <span>{btn.label}</span>;
}

function getButtonLabel(btn: Btn) {
  return OPERATOR_ARIA_LABELS[btn.key] ?? (btn.label || btn.key);
}

export default function HeroCalculator() {
  const [state, setState] = useState<State>(INIT);

  const press = useCallback((key: string) => {
    setState(s => {
      const { display, expr, justComputed, memory, lastAnswer, angleMode } = s;
      const cur = parseFloat(display);

      const immediate = (result: number): State => ({
        ...s, display: fmt(result), lastAnswer: fmt(result), expr: "", justComputed: true,
      });
      const appendOp = (op: string): State => {
        if (display === "Error") return { ...INIT, memory, lastAnswer, angleMode };
        const newExpr = justComputed ? display + op : expr + display + op;
        return { ...s, display: "0", expr: newExpr, justComputed: false };
      };

      if (key === "AC") return { ...INIT, memory, lastAnswer, angleMode };
      if (key === "Back") {
        if (justComputed || display === "Error") return { ...s, display: "0", justComputed: false };
        if (display.length <= 1 || (display.length === 2 && display.startsWith("-"))) return { ...s, display: "0" };
        return { ...s, display: display.slice(0, -1) };
      }
      if ("0123456789".includes(key)) {
        if (justComputed) return { ...s, display: key, expr: "", justComputed: false };
        if (display === "Error" || display === "0") return { ...s, display: key, justComputed: false };
        if (display.length >= 14) return s;
        return { ...s, display: display + key, justComputed: false };
      }
      if (key === ".") {
        if (justComputed) return { ...s, display: "0.", expr: "", justComputed: false };
        if (display.includes(".")) return s;
        return { ...s, display: display + ".", justComputed: false };
      }
      if (key === "TOGGLE") return { ...s, angleMode: angleMode === "deg" ? "rad" : "deg" };
      if (key === "pi") return { ...s, display: fmt(Math.PI), justComputed: true };
      if (key === "e")  return { ...s, display: fmt(Math.E),  justComputed: true };
      if (key === "sin")  return immediate(Math.sin(toRad(cur, angleMode)));
      if (key === "cos")  return immediate(Math.cos(toRad(cur, angleMode)));
      if (key === "tan")  return immediate(Math.tan(toRad(cur, angleMode)));
      if (key === "asin") return immediate(isNaN(cur) || Math.abs(cur) > 1 ? NaN : fromRad(Math.asin(cur), angleMode));
      if (key === "acos") return immediate(isNaN(cur) || Math.abs(cur) > 1 ? NaN : fromRad(Math.acos(cur), angleMode));
      if (key === "atan") return immediate(fromRad(Math.atan(cur), angleMode));
      if (key === "ln")   return immediate(cur <= 0 ? NaN : Math.log(cur));
      if (key === "log")  return immediate(cur <= 0 ? NaN : Math.log10(cur));
      if (key === "sqrt") return immediate(cur < 0 ? NaN : Math.sqrt(cur));
      if (key === "cbrt") return immediate(Math.cbrt(cur));
      if (key === "sq")   return immediate(cur * cur);
      if (key === "cube") return immediate(cur * cur * cur);
      if (key === "exp")  return immediate(Math.exp(cur));
      if (key === "10x")  return immediate(Math.pow(10, cur));
      if (key === "1/x")  return immediate(cur === 0 ? NaN : 1 / cur);
      if (key === "n!")   return immediate(factorial(Math.round(cur)));
      if (key === "neg") return { ...s, display: display === "0" ? "0" : display.startsWith("-") ? display.slice(1) : "-" + display };
      if (key === "%")    return immediate(cur / 100);
      if (key === "RND")  return immediate(Math.random());
      if (key === "+")    return appendOp("+");
      if (key === "-")    return appendOp("-");
      if (key === "*")    return appendOp("*");
      if (key === "/")    return appendOp("/");
      if (key === "pow")  return appendOp("^");
      if (key === "yroot") return appendOp("^(1/");
      if (key === "EXP") {
        if (display.includes("e")) return s;
        return { ...s, display: display + "e", justComputed: false };
      }
      if (key === "(") {
        if (justComputed) return { ...s, display: "0", expr: "(", justComputed: false };
        if (expr === "" && display === "0") return { ...s, display: "0", expr: "(", justComputed: false };
        return { ...s, display: "0", expr: expr + display + "*(", justComputed: false };
      }
      if (key === ")") return { ...s, display: "0", expr: expr + display + ")", justComputed: false };
      if (key === "M+")  return { ...s, memory: memory + cur };
      if (key === "M-")  return { ...s, memory: memory - cur };
      if (key === "MR")  return { ...s, display: fmt(memory), justComputed: true };
      if (key === "Ans") return { ...s, display: lastAnswer, justComputed: true };
      if (key === "=") {
        if (display === "Error") return { ...INIT, memory, lastAnswer, angleMode };
        let full = expr + display;
        const opens = (full.match(/\(/g) || []).length;
        const closes = (full.match(/\)/g) || []).length;
        full += ")".repeat(Math.max(0, opens - closes));
        const result = safeEval(full);
        return { ...s, display: result, expr: "", lastAnswer: result, justComputed: true, memory };
      }
      return s;
    });
  }, []);

  const { display, expr, angleMode, memory } = state;

  const fmtDisplay = (d: string) => {
    if (d === "Error") return "Error";
    if (d.endsWith(".") || d.endsWith("e") || d.endsWith("e-") || d.endsWith("e+")) return d;
    const n = parseFloat(d);
    if (isNaN(n)) return d;
    if (d.length <= 13) return d;
    return n.toExponential(5);
  };

  const sciBtn = (type: Btn["type"]) => {
    const base = "flex items-center justify-center h-9 sm:h-10 font-medium transition-all duration-75 active:scale-95 touch-manipulation text-[10px] sm:text-[11px]";
    switch (type) {
      case "sci": return `${base} bg-zinc-100 dark:bg-zinc-700 text-zinc-700 dark:text-zinc-200 hover:bg-zinc-200 dark:hover:bg-zinc-600 active:bg-zinc-300`;
      case "op":  return `${base} bg-primary/85 text-primary-foreground hover:bg-primary active:bg-primary/70 text-lg sm:text-xl font-extrabold leading-none`;
      case "num": return `${base} bg-white dark:bg-zinc-800 text-zinc-900 dark:text-white hover:bg-zinc-50 dark:hover:bg-zinc-700 active:bg-zinc-100 text-sm sm:text-[15px]`;
      case "eq":  return `${base} bg-amber-500 text-white hover:bg-amber-400 active:bg-amber-600 text-lg sm:text-xl font-extrabold leading-none`;
      case "mem": return `${base} bg-indigo-50 dark:bg-indigo-950/60 text-indigo-700 dark:text-indigo-300 hover:bg-indigo-100 dark:hover:bg-indigo-900 active:bg-indigo-200`;
      default:    return base;
    }
  };

  const mobBtn = (type: Btn["type"]) => {
    const base = "flex items-center justify-center h-[72px] rounded-2xl font-semibold text-xl transition-all duration-75 active:scale-95 touch-manipulation select-none";
    switch (type) {
      case "fn":  return `${base} bg-zinc-200 dark:bg-zinc-600 text-zinc-800 dark:text-zinc-100 hover:bg-zinc-300 dark:hover:bg-zinc-500`;
      case "op":  return `${base} bg-primary text-primary-foreground hover:opacity-90 active:opacity-70 shadow-sm`;
      case "num": return `${base} bg-white dark:bg-zinc-700 text-zinc-900 dark:text-white hover:bg-zinc-50 dark:hover:bg-zinc-600 shadow-sm`;
      case "eq":  return `${base} bg-amber-500 text-white hover:bg-amber-400 active:bg-amber-600 shadow-sm font-bold`;
      default:    return base;
    }
  };

  return (
    <>
      {/* -R MOBILE compact calculator (hidden on sm+) -R */}
      <div className="sm:hidden w-full max-w-[360px] mx-auto rounded-2xl border border-border shadow-xl overflow-hidden select-none">
        {/* Display */}
        <div className="bg-zinc-900 px-5 pt-4 pb-4 flex flex-col items-end min-h-[100px] justify-end">
          <p className="text-zinc-500 text-xs font-mono truncate max-w-full mb-1 h-4">{expr || "\u00A0"}</p>
          <p
            className="text-white font-light font-mono tracking-tight w-full text-right leading-none transition-all"
            style={{ fontSize: fmtDisplay(display).length > 10 ? "1.6rem" : fmtDisplay(display).length > 7 ? "2rem" : "2.6rem" }}
          >
            {fmtDisplay(display)}
          </p>
        </div>

        {/* Button grid - 4 columns with gap */}
        <div className="bg-zinc-100 dark:bg-zinc-800 p-2.5 grid grid-cols-4 gap-2.5">
          {MOB_ROWS.map((row, ri) =>
            row.map((btn) => (
              <button
                key={`mob-${ri}-${btn.key}`}
                onClick={() => press(btn.key)}
                aria-label={getButtonLabel(btn)}
                style={btn.cols ? { gridColumn: `span ${btn.cols}` } : undefined}
                className={mobBtn(btn.type)}
              >
                {btn.label}
              </button>
            ))
          )}
        </div>
      </div>

      {/* -R DESKTOP scientific calculator (hidden below sm) -R */}
      <div className="hidden sm:block w-full max-w-[420px] sm:max-w-[480px] mx-auto lg:mx-0 rounded-2xl border border-border shadow-xl overflow-hidden select-none">
        {/* Display */}
        <div className="bg-zinc-900 px-4 pt-3 pb-3 flex flex-col justify-end items-end min-h-[80px] sm:min-h-[90px]">
          <div className="flex items-center gap-2 w-full justify-between mb-1">
            <div className="flex items-center gap-2">
              <span className={`text-[9px] font-bold px-1.5 py-0.5 rounded ${angleMode === "deg" ? "bg-primary text-white" : "bg-zinc-700 text-zinc-400"}`}>DEG</span>
              <span className={`text-[9px] font-bold px-1.5 py-0.5 rounded ${angleMode === "rad" ? "bg-primary text-white" : "bg-zinc-700 text-zinc-400"}`}>RAD</span>
              {memory !== 0 && <span className="text-[9px] font-bold text-amber-400">M</span>}
            </div>
            <p className="text-zinc-500 text-[10px] font-mono truncate text-right max-w-[60%]">{expr}</p>
          </div>
          <p
            className="text-white font-mono font-light tracking-tight w-full text-right leading-none transition-all"
            style={{ fontSize: fmtDisplay(display).length > 10 ? "1.5rem" : fmtDisplay(display).length > 7 ? "1.9rem" : "2.4rem" }}
          >
            {fmtDisplay(display)}
          </p>
        </div>

        {/* 10-column scientific grid */}
        <div className="grid grid-cols-10 gap-px bg-zinc-300 dark:bg-zinc-600">
          {SCI_ROWS[0].slice(0, 3).map(btn => (
            <button key={btn.key} onClick={() => press(btn.key)} className={sciBtn(btn.type)} aria-label={getButtonLabel(btn)}>
              <BtnLabel btn={btn} />
            </button>
          ))}
          <button
            onClick={() => press("TOGGLE")}
            className="col-span-2 flex items-center justify-center gap-1 h-9 sm:h-10 bg-zinc-100 dark:bg-zinc-700 hover:bg-zinc-200 dark:hover:bg-zinc-600 active:bg-zinc-300 transition-all text-[9px] font-bold touch-manipulation"
            aria-label="Toggle angle mode"
          >
            <span className={angleMode === "deg" ? "text-primary" : "text-zinc-400"}>DEG</span>
            <span className="text-zinc-400">|</span>
            <span className={angleMode === "rad" ? "text-primary" : "text-zinc-400"}>RAD</span>
          </button>
          {SCI_ROWS[0].slice(3).map(btn => (
            <button key={btn.key} onClick={() => press(btn.key)} className={sciBtn(btn.type)} aria-label={getButtonLabel(btn)}>
              <BtnLabel btn={btn} />
            </button>
          ))}
          {SCI_ROWS.slice(1).map((row, ri) =>
            row.map(btn => (
              <button key={`sci-${ri}-${btn.key}`} onClick={() => press(btn.key)} className={sciBtn(btn.type)} aria-label={getButtonLabel(btn)}>
                <BtnLabel btn={btn} />
              </button>
            ))
          )}
        </div>
      </div>
    </>
  );
}


